if [[ "$*" == *fullSweep* || "$*" == *all* ]]
then

    types=(
        int16 int16
        cint16 int16
        int32 int16
        cint32 int16
        cint16 cint16
        int32 int32
        cint32 int32
        cint32 cint32
        float float
        cfloat float
        cfloat cfloat
    )

    # Original ideal set of params to sweep across
    lengths=(4 8 12 16 20 32 44 56 64 96 128 156 188 220 240)
    windows=(4 8 16 32 64 128 156 188 220 256 320 384 512 1024)
    cascades=(1 2 3 4 5 6 7)

    #reduced to limit number of tests
    # one type combo currently
    types=(
        cint16 int16
    )
    lengths=(16 20 44 56 96 128 188 240)
    windows=(16 32 64 128 188 256 320 512 1024)
    # todo cascade
    cascades=(1)

    interps=(1)
    decimates=(2 3 5 7)

    for (( typeI=0; typeI<${#types[@]}; typeI+=2 )); do
        echo "${types[$typeI]},${types[`expr $typeI + 1 `]}"
        dType=${types[$typeI]}
        cType=${types[`expr $typeI + 1 `]}
        # Scrape int number from coef type
        shift=${cType#*int}
        if [[ $cType == *float ]]; then
            shift=0
        fi
        for fLen in "${lengths[@]}"; do
            for iRate in "${interps[@]}"; do
                for dRate in "${decimates[@]}"; do
                    for cLen in "${cascades[@]}"; do
                        redWindows=(${windows[@]})
                        # to reduce number of tests, limited number of windows
                        # for cascades
                        if [ $cLen -gt 1 ]; then
                            redWindows=(256 1024)
                        fi
                        # Always use a window of FIR Len
                        test_arr[$LINENO]="make all DATA_TYPE=$dType COEFF_TYPE=$cType  FIR_LEN=$fLen DECIMATE_FACTOR=$dRate CASC_LEN=$cLen SHIFT=$shift INPUT_WINDOW_VSIZE=$fLen"
                        #echo ${redWindows[@]}
                        for wSize in "${redWindows[@]}"; do
                            if [ $wSize -gt $fLen ]
                            then
                                #echo "DATA_TYPE=$dType COEFF_TYPE=$cType  FIR_LEN=$fLen  CASC_LEN=$cLen SHIFT=$shift"
                                test_arr[$LINENO]="make all DATA_TYPE=$dType COEFF_TYPE=$cType  FIR_LEN=$fLen DECIMATE_FACTOR=$dRate CASC_LEN=$cLen SHIFT=$shift INPUT_WINDOW_VSIZE=$wSize"
                                #test_arr[${#test_arr[*]}]
                                #echo "wSize $wSize"
                            fi
                        done #wSize
                    done #cLen
                done #dRate
            done #iRate
        done #fLen
    done #typeI
fi

